// App.js - React Native OAuth Implementation (SECURE)
import React, { useState } from 'react';
import { View, Button, Text, StyleSheet, Alert } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';

WebBrowser.maybeCompleteAuthSession();

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [userInfo, setUserInfo] = useState(null);

  // SECURE: Use PKCE (Proof Key for Code Exchange) - NO client secret needed
  const discovery = {
    authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
    tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: 'mobile_app_client_123',
      // NO CLIENT SECRET - Use PKCE instead
      usePKCE: true,
      scopes: ['openid', 'profile', 'email'],
      redirectUri: AuthSession.makeRedirectUri({
        scheme: 'yourapp'
      }),
    },
    discovery
  );

  React.useEffect(() => {
    if (response?.type === 'success') {
      const { code } = response.params;
      exchangeCodeForToken(code);
    }
  }, [response]);

  const exchangeCodeForToken = async (code) => {
    try {
      // SECURE: Token exchange happens through your backend proxy
      const tokenResponse = await fetch('https://your-backend.com/api/token-exchange', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          code: code,
          redirectUri: AuthSession.makeRedirectUri({ scheme: 'yourapp' }),
          codeVerifier: request.codeVerifier, // PKCE verifier
        }),
      });

      const tokens = await tokenResponse.json();
      setAccessToken(tokens.access_token);
      fetchUserInfo(tokens.access_token);
    } catch (error) {
      Alert.alert('Error', 'Failed to exchange token');
    }
  };

  const fetchUserInfo = async (token) => {
    try {
      const response = await fetch('https://your-auth-server.com/userinfo', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      const data = await response.json();
      setUserInfo(data);
    } catch (error) {
      Alert.alert('Error', 'Failed to fetch user info');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Secure OAuth App</Text>
      
      {!accessToken ? (
        <Button
          disabled={!request}
          title="Login with OAuth"
          onPress={() => promptAsync()}
        />
      ) : (
        <View>
          <Text style={styles.success}>✓ Authenticated</Text>
          {userInfo && (
            <View style={styles.userInfo}>
              <Text>Email: {userInfo.email}</Text>
              <Text>Name: {userInfo.name}</Text>
            </View>
          )}
          <Button title="Logout" onPress={() => setAccessToken(null)} />
        </View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: 20,
  },
  title: {
    fontSize: 24,
    marginBottom: 20,
  },
  success: {
    color: 'green',
    fontSize: 18,
    marginBottom: 10,
  },
  userInfo: {
    marginVertical: 20,
  },
});

export default App;